/*! sql-highlight - Local SQL syntax highlighter with IDE-style colors */
(function(global){
  'use strict';
  
  // Keywords with proper SQL word boundaries
  var SQL_KEYWORDS = /\b(CREATE|TABLE|ALTER|DROP|INSERT|UPDATE|DELETE|SELECT|FROM|WHERE|JOIN|INNER|LEFT|RIGHT|FULL|OUTER|ON|AND|OR|NOT|IN|EXISTS|BETWEEN|LIKE|IS|NULL|GROUP|BY|ORDER|HAVING|LIMIT|OFFSET|UNION|INTERSECT|EXCEPT|AS|WITH|CASE|WHEN|THEN|ELSE|END|PRIMARY|KEY|FOREIGN|REFERENCES|UNIQUE|CHECK|DEFAULT|CONSTRAINT|INDEX|VIEW|TRIGGER|PROCEDURE|FUNCTION|RETURN|VALUES|SERIAL|BIGSERIAL|SMALLSERIAL|AUTO_INCREMENT|UNSIGNED|SIGNED|BOOLEAN|CHAR|VARCHAR|TEXT|BLOB|INT|INTEGER|BIGINT|SMALLINT|DECIMAL|NUMERIC|FLOAT|DOUBLE|DATE|TIME|DATETIME|TIMESTAMP|YEAR|INTERVAL|BINARY|VARBINARY|JSON|JSONB|ARRAY|UUID|BYTEA|ENUM|SET|COLLATE|CHARSET|ENGINE|CASCADE|RESTRICT|NO|ACTION|IDENTITY|NVARCHAR|NCHAR|UNIQUEIDENTIFIER|DATETIME2|DATETIMEOFFSET|NUMBER|VARCHAR2|CLOB|RAW|SEQUENCE|PRAGMA|CROSS|USING)\b/gi;
  var OPERATORS = /([(),.;=<>!+\-*/%])/g;
  var STRING_LITERAL = /'[^']*'|"[^"]*"/g;
  var COMMENT = /--.*/g;
  var BLOCK_COMMENT = /\/\*[\s\S]*?\*\//g;
  
  function escapeHtml(text) {
    return text
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;');
  }
  
  function highlightSQL(sql) {
    if (!sql) return '';
    
    var result = '';
    var lastIndex = 0;
    var matches = [];
    
    // Collect all matches with their positions and types
    var regex;
    
    // Block comments
    regex = /\/\*[\s\S]*?\*\//g;
    var match;
    while ((match = regex.exec(sql)) !== null) {
      matches.push({ start: match.index, end: match.index + match[0].length, type: 'comment', text: match[0] });
    }
    
    // Line comments
    regex = /--.*/g;
    while ((match = regex.exec(sql)) !== null) {
      matches.push({ start: match.index, end: match.index + match[0].length, type: 'comment', text: match[0] });
    }
    
    // String literals
    regex = /'[^']*'|"[^"]*"/g;
    while ((match = regex.exec(sql)) !== null) {
      matches.push({ start: match.index, end: match.index + match[0].length, type: 'string', text: match[0] });
    }
    
    // Keywords
    regex = /\b(CREATE|TABLE|ALTER|DROP|INSERT|UPDATE|DELETE|SELECT|FROM|WHERE|JOIN|INNER|LEFT|RIGHT|FULL|OUTER|ON|AND|OR|NOT|IN|EXISTS|BETWEEN|LIKE|IS|NULL|GROUP|BY|ORDER|HAVING|LIMIT|OFFSET|UNION|INTERSECT|EXCEPT|AS|WITH|CASE|WHEN|THEN|ELSE|END|PRIMARY|KEY|FOREIGN|REFERENCES|UNIQUE|CHECK|DEFAULT|CONSTRAINT|INDEX|VIEW|TRIGGER|PROCEDURE|FUNCTION|RETURN|VALUES|SERIAL|BIGSERIAL|SMALLSERIAL|AUTO_INCREMENT|UNSIGNED|SIGNED|BOOLEAN|CHAR|VARCHAR|TEXT|BLOB|INT|INTEGER|BIGINT|SMALLINT|DECIMAL|NUMERIC|FLOAT|DOUBLE|DATE|TIME|DATETIME|TIMESTAMP|YEAR|INTERVAL|BINARY|VARBINARY|JSON|JSONB|ARRAY|UUID|BYTEA|ENUM|SET|COLLATE|CHARSET|ENGINE|CASCADE|RESTRICT|NO|ACTION|IDENTITY|NVARCHAR|NCHAR|UNIQUEIDENTIFIER|DATETIME2|DATETIMEOFFSET|NUMBER|VARCHAR2|CLOB|RAW|SEQUENCE|PRAGMA|CROSS|USING)\b/gi;
    while ((match = regex.exec(sql)) !== null) {
      // Check if this position is not inside a comment or string
      var inHigher = matches.some(function(m) { return match.index >= m.start && match.index < m.end; });
      if (!inHigher) {
        matches.push({ start: match.index, end: match.index + match[0].length, type: 'keyword', text: match[0] });
      }
    }
    
    // Sort matches by position
    matches.sort(function(a, b) { return a.start - b.start; });
    
    // Remove overlapping matches (keep the first one)
    var filtered = [];
    matches.forEach(function(m) {
      var overlaps = filtered.some(function(f) { return m.start < f.end && m.end > f.start; });
      if (!overlaps) {
        filtered.push(m);
      }
    });
    
    // Build result with highlighting
    lastIndex = 0;
    filtered.forEach(function(m) {
      result += escapeHtml(sql.substring(lastIndex, m.start));
      
      if (m.type === 'keyword') {
        result += '<span class="sql-keyword">' + escapeHtml(m.text) + '</span>';
      } else if (m.type === 'string') {
        result += '<span class="sql-string">' + escapeHtml(m.text) + '</span>';
      } else if (m.type === 'comment') {
        result += '<span class="sql-comment">' + escapeHtml(m.text) + '</span>';
      }
      
      lastIndex = m.end;
    });
    
    // Add remaining text
    result += escapeHtml(sql.substring(lastIndex));
    
    return result;
  }
  
  var sqlHighlight = {
    highlight: highlightSQL
  };
  
  // Browser global
  if (typeof window !== 'undefined') {
    window.sqlHighlight = sqlHighlight;
  }
  
  // CommonJS/Node.js
  if (typeof module !== 'undefined' && module.exports) {
    module.exports = sqlHighlight;
  }
  
})(typeof window !== 'undefined' ? window : global);
